3	import (
4		"net"
5		"net/url"
6		"strings"
7	)
8	
9	const (
10		BillingModePaid         = "paid"
11		BillingModeSubscription = "subscription"
12		BillingModeLocal        = "local"
13	)
14	
15	// BillingModeFor classifies a session's cost basis. It is the single
16	// write-time source of truth for the sharded session index and legacy reindex.
17	func BillingModeFor(harness, surface, baseURL string) string {
18		return billingModeFor(harness, surface, baseURL)
19	}
20	
21	func billingModeFor(harness, surface, baseURL string) string {
22		h := normalizeBillingPart(harness)
23		s := normalizeBillingPart(surface)
24	
25		if isLocalBaseURL(baseURL) {
26			return BillingModeLocal
27		}
28	
29		switch h {
30		case "agent", "virtual", "script", "lmstudio", "ollama", "vllm", "omlx":
31			return BillingModeLocal
32		case "claude", "claude-code", "codex", "gemini", "gemini-cli":
33			return BillingModeSubscription
34		case "openrouter", "openai", "anthropic":
35			return BillingModePaid
36		}
37	
38		switch s {
39		case "claude", "codex", "gemini":
40			return BillingModeSubscription
41		case "local", "virtual", "script":
42			return BillingModeLocal
43		case "openai-compat", "embedded-openai", "embedded-anthropic", "anthropic":
44			return BillingModePaid
45		}
46	
47		// Unknown non-local work is treated as paid rather than local so cash-like
48		// API paths do not disappear from the paid bucket silently.
49		return BillingModePaid
50	}
51	
52	func ValidateBillingMode(mode string) bool {
53		switch mode {
54		case BillingModePaid, BillingModeSubscription, BillingModeLocal:
55			return true
56		default:
57			return false
58		}
59	}
60	
61	func normalizeBillingPart(s string) string {
62		s = strings.ToLower(strings.TrimSpace(s))
63		s = strings.ReplaceAll(s, "_", "-")
64		return s
65	}
66	
67	func isLocalBaseURL(raw string) bool {
68		raw = strings.TrimSpace(raw)
69		if raw == "" {
70			return false
71		}
72		u, err := url.Parse(raw)
73		if err != nil {
74			return false
75		}
76		host := u.Hostname()
77		if host == "" {
78			host = u.Host
79		}
80		host = strings.Trim(strings.ToLower(host), "[]")
81		if host == "" {
82			return false
83		}
84		if host == "localhost" || strings.HasSuffix(host, ".localhost") {
85			return true
86		}
87		ip := net.ParseIP(host)
88		if ip == nil {
89			return false
90		}
91		return ip.IsLoopback() || ip.IsPrivate()
92	}
