288	func ReadSessionIndex(logDir string, q SessionIndexQuery) ([]SessionIndexEntry, error) {
289		files, err := SessionIndexShardFiles(logDir, q)
290		if err != nil {
291			return nil, err
292		}
293		var out []SessionIndexEntry
294		if q.DefaultRecent && q.StartedAfter == nil && q.StartedBefore == nil {
295			out, err = readRecentSessionIndexFiles(files, 1000)
296		} else {
297			out, err = readSessionIndexFiles(files, q)
298		}
299		if err != nil {
300			return nil, err
301		}
302		if len(out) == 0 && q.DefaultRecent && q.StartedAfter == nil && q.StartedBefore == nil {
303			files, err = SessionIndexShardFiles(logDir, SessionIndexQuery{})
304			if err != nil {
305				return nil, err
306			}
307			out, err = readSessionIndexFiles(files, q)
308			if err != nil {
309				return nil, err
310			}
311		}
312		sort.Slice(out, func(i, j int) bool {
313			return out[i].StartedAt.After(out[j].StartedAt)
314		})
315		return out, nil
316	}
317	
318	func readRecentSessionIndexFiles(files []string, perFile int) ([]SessionIndexEntry, error) {
319		var out []SessionIndexEntry
320		for _, file := range files {
321			data, err := os.ReadFile(file)
322			if os.IsNotExist(err) {
323				continue
324			}
325			if err != nil {
326				return nil, err
327			}
328			lines := bytes.Split(bytes.TrimSpace(data), []byte{'\n'})
329			start := 0
330			if perFile > 0 && len(lines) > perFile {
331				start = len(lines) - perFile
332			}
333			for _, line := range lines[start:] {
334				if len(bytes.TrimSpace(line)) == 0 {
335					continue
336				}
337				var entry SessionIndexEntry
338				if err := json.Unmarshal(line, &entry); err == nil {
339					out = append(out, entry)
340				}
341			}
342		}
343		return out, nil
344	}
345	
346	func readSessionIndexFiles(files []string, q SessionIndexQuery) ([]SessionIndexEntry, error) {
347		var out []SessionIndexEntry
348		for _, file := range files {
349			err := ForEachJSONL[SessionIndexEntry](file, func(entry SessionIndexEntry) error {
350				if !sessionIndexEntryInRange(entry, q) {
351					return nil
352				}
353				out = append(out, entry)
354				return nil
355			})
356			if err != nil {
357				return nil, err
358			}
359		}
360		return out, nil
361	}
362	
363	func FindSessionIndex(logDir, id string) (SessionIndexEntry, bool, error) {
364		files, err := SessionIndexShardFiles(logDir, SessionIndexQuery{})
365		if err != nil {
366			return SessionIndexEntry{}, false, err
367		}
368		for _, file := range files {
369			var found SessionIndexEntry
370			ok := false
371			err := ForEachJSONL[SessionIndexEntry](file, func(entry SessionIndexEntry) error {
372				if entry.ID == id {
373					found = entry
374					ok = true
375					return fmt.Errorf("found")
376				}
377				return nil
378			})
379			if ok {
380				return found, true, nil
381			}
382			if err != nil && err.Error() != "found" {
383				return SessionIndexEntry{}, false, err
384			}
385		}
386		return SessionIndexEntry{}, false, nil
