416	func ReindexLegacySessions(projectRoot, logDir string) (int, error) {
417		legacyPath := filepath.Join(logDir, LegacySessionsFileName)
418		readPath := legacyPath
419		if _, err := os.Stat(readPath); os.IsNotExist(err) {
420			readPath = filepath.Join(logDir, LegacySessionsRenameName)
421			if _, legacyErr := os.Stat(readPath); os.IsNotExist(legacyErr) {
422				return 0, nil
423			} else if legacyErr != nil {
424				return 0, legacyErr
425			}
426		} else if err != nil {
427			return 0, err
428		}
429	
430		existing, err := existingSessionIndexIDs(logDir)
431		if err != nil {
432			return 0, err
433		}
434		count := 0
435		err = ForEachJSONL[SessionEntry](readPath, func(entry SessionEntry) error {
436			if entry.ID == "" {
437				return nil
438			}
439			if _, ok := existing[entry.ID]; ok {
440				return nil
441			}
442			idx := SessionIndexEntryFromLegacy(projectRoot, entry)
443			if err := AppendSessionIndex(logDir, idx, entry.Timestamp.UTC()); err != nil {
444				return err
445			}
446			existing[entry.ID] = struct{}{}
447			count++
448			return nil
449		})
450		if err != nil {
451			return count, err
452		}
453		if readPath == legacyPath {
454			renamed := filepath.Join(logDir, LegacySessionsRenameName)
455			if _, err := os.Stat(renamed); os.IsNotExist(err) {
456				if err := os.Rename(legacyPath, renamed); err != nil {
457					return count, err
458				}
459			}
460		}
461		return count, nil
462	}
