625	func bodiesFromResultJSON(data []byte) (string, string) {
626		var raw map[string]any
627		if err := json.Unmarshal(data, &raw); err != nil {
628			return "", ""
629		}
630		response := firstString(raw, "response", "output", "final_text", "finalText", "detail")
631		stderr := firstString(raw, "stderr", "error")
632		return response, stderr
633	}
