635	func bodiesFromNativeLog(path string) (string, string) {
636		f, err := os.Open(path)
637		if err != nil {
638			return "", ""
639		}
640		defer f.Close()
641		var response, stderr string
642		scanner := bufio.NewScanner(f)
643		scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)
644		for scanner.Scan() {
645			var raw map[string]any
646			if err := json.Unmarshal(scanner.Bytes(), &raw); err != nil {
647				continue
648			}
649			if s := firstNestedString(raw, []string{"data", "final_text"}, []string{"data", "finalText"}, []string{"final_text"}, []string{"finalText"}); s != "" {
650				response = s
651			}
652			if s := firstNestedString(raw, []string{"data", "error"}, []string{"error"}, []string{"stderr"}); s != "" {
653				stderr = s
654			}
655		}
656		return response, stderr
657	}
