659	func firstString(raw map[string]any, keys ...string) string {
660		for _, key := range keys {
661			if s, ok := raw[key].(string); ok && s != "" {
662				return s
663			}
664		}
665		return ""
666	}
667	
668	func firstNestedString(raw map[string]any, paths ...[]string) string {
669		for _, path := range paths {
670			cur := any(raw)
671			for _, key := range path {
672				m, ok := cur.(map[string]any)
673				if !ok {
674					cur = nil
675					break
676				}
677				cur = m[key]
678			}
679			if s, ok := cur.(string); ok && s != "" {
680				return s
681			}
682		}
683		return ""
684	}
685

670		}
671		return nil, false
672	}
